```Java
import com.microsoft.z3.*;
import java.util.HashMap;

public class Myfunction_2{
    public static void main(String[] args) {
        HashMap<String, String> m = new HashMap<String,String>();
        Context ctx = new Context(m);

        IntExpr a = ctx.mkIntConst("a");
        IntExpr b = ctx.mkIntConst("b");
        IntExpr c = ctx.mkIntConst("c");
        Optimize opt = ctx.mkOptimize();
      
        // let a + 2*b + 3*c = 22
        BoolExpr formula = ctx.mkEq(
            ctx.mkAdd(
                ctx.mkMul(a,ctx.mkInt(1)), 
                ctx.mkMul(b,ctx.mkInt(2)), 
                ctx.mkMul(c,ctx.mkInt(3))
                ),
            ctx.mkInt(22)
            );
        System.out.println("formula : " + formula);

        /* constraints definition */
        BoolExpr constraint_1 = ctx.mkGe(a, ctx.mkInt(0));  // a >= 0
        BoolExpr constraint_2 = ctx.mkLt(a, ctx.mkInt(10)); // a < 10
        BoolExpr constraint_3 = ctx.mkGe(b, ctx.mkInt(0));  // b >= 0
        BoolExpr constraint_4 = ctx.mkLt(b, ctx.mkInt(10)); // b < 10
        BoolExpr constraint_5 = ctx.mkGe(c, ctx.mkInt(0));  // c >= 0
        BoolExpr constraint_6 = ctx.mkLt(c, ctx.mkInt(10)); // c < 10
        
        /* add constraints into the optimizing solver */           
        opt.Add(
            formula,
            constraint_1,
            constraint_2,
            constraint_3,
            constraint_4,
            constraint_5,
            constraint_6
            );  
        
         /* the optimize goal */
        Optimize.Handle mc = opt.MkMaximize(c);
        
        if(opt.Check() == Status.SATISFIABLE)
        {
            Model model = opt.getModel();
            System.out.println("model : " + model);

            Expr ma = model.eval(a,false); 
            Expr mb = model.eval(b,false); 
  
            System.out.println("\nma = " + ma);
            System.out.println("\nmb = " + mb);   

            System.out.println("\nmc = " + mc);
            System.out.println("upperc = " + mc.getUpper());
            System.out.println("lowerc = " + mc.getLower());
        }else
        {
            System.out.println("not satisfiable");
        }   
    }
}
